body:
### Version

Yosys 0.54 (git sha1 db72ec3bd, g++ 12.2.0-14+deb12u1 -fPIC -O3)

### On which OS did this happen?

Linux

### Reproduction Steps

Yosys gives the right result, but cxxrtl does not 
Yosys script that gives the right result
```sv
read_verilog -sv <<EOT
module countbits;
    logic [7:0] in_d;
    logic [3:0] cnt;

    assign cnt = $countbits(in_d, 1'b1);
    assign in_d = 8'h8F; 

    always_comb assert(cnt == 4'd5);
endmodule
EOT

prep -top countbits
chformal -lower
select countbits
sat -prove-asserts -verify
```

Nevertheless when I run this script 
```sv
read_verilog -sv << EOT
module countbits (
    input logic [7:0] in_d,
    output logic [3:0] cnt
);
    assign cnt = $countbits(in_d, 1'b1, 1'bx);
endmodule
EOT
write_cxxrtl countbits.cc
```

I use this testbench.cpp
```cpp
#include "countbits.cc" // CXXRTL generated header for the module
#include <iostream>
#include <iomanip>
#include <cstdint>
#include <string>
#include <sstream>
#include <type_traits>

// Template helpers to detect and work with both value<> and wire<> types
template<typename T>
struct has_curr {
    template<typename U>
    static auto test(int) -> decltype(std::declval<U>().curr, std::true_type{});
    template<typename>
    static std::false_type test(...);
    using type = decltype(test<T>(0));
    static constexpr bool value = type::value;
};
// Helper function to get port value - works with both value<> and wire<>
template<typename T, typename PortType>
typename std::enable_if<has_curr<PortType>::value, T>::type
_get_port_value(const PortType& port) {
    return port.curr.template get<T>();
}
template<typename T, typename PortType>
typename std::enable_if<!has_curr<PortType>::value, T>::type
_get_port_value(const PortType& port) {
    return port.template get<T>();
}
// Helper function to get port bit - works with both value<> and wire<>
template<typename PortType>
typename std::enable_if<has_curr<PortType>::value, bool>::type
_get_port_value(const PortType& port, int bit) {
    return port.curr.bit(bit);
}
template<typename PortType>
typename std::enable_if<!has_curr<PortType>::value, bool>::type
_get_port_value(const PortType& port, int bit) {
    return port.bit(bit);
}
// Helper function to get wide port value - works with both value<> and wire<>
template<typename PortType>
auto _get_port_value_wide(const PortType& port) -> typename std::enable_if<has_curr<PortType>::value, decltype(port.curr)>::type {
    return port.curr;
}
template<typename PortType>
auto _get_port_value_wide(const PortType& port) -> typename std::enable_if<!has_curr<PortType>::value, PortType>::type {
    return port;
}
// Helper function to set port value - works with both value<> and wire<>
template<typename T, typename PortType>
typename std::enable_if<has_curr<PortType>::value, void>::type
_set_port_value(PortType& port, T value) {
    port.next.template set<T>(value);
}
template<typename T, typename PortType>
typename std::enable_if<!has_curr<PortType>::value, void>::type
_set_port_value(PortType& port, T value) {
    port.template set<T>(value);
}
// Helper function to set wide port value - works with both value<> and wire<>
template<typename PortType, typename ValueType>
typename std::enable_if<has_curr<PortType>::value, void>::type
_set_port_value_wide(PortType& port, const ValueType& value) {
    port.next = value;
}
template<typename PortType, typename ValueType>
typename std::enable_if<!has_curr<PortType>::value, void>::type
_set_port_value_wide(PortType& port, const ValueType& value) {
    port = value;
}

int main(int argc, char** argv) {
    cxxrtl_design::p_countbits countbits_i; // DUT instance

    // Declare input variables
    uint8_t in_d;

    in_d = 0x8F;

    // Apply inputs to DUT
    _set_port_value<uint8_t>(countbits_i.p_in__d, in_d);

    // Handle reset, clock toggling, and evaluation
    // No clock found, performing bounded steps for combinational logic to settle
    for (int settle_step = 0; settle_step < 20; settle_step++) {
        countbits_i.step();
    }

    // Display the output values
    std::cout << "cnt = ";
    for (int i = 3; i >= 0; --i) {
        std::cout << (_get_port_value(countbits_i.p_cnt, i) ? '1' : '0');
    }
    std::cout << std::endl;

    return 0;
}
```

And this is the command I ran
```sh
g++ -std=c++17 -O0 -I$(yosys-config --datdir)/include/backends/cxxrtl/runtime testbench.cpp -I. -o sim && ./sim
```



### Expected Behavior

I would have expected 
```txt
cnt = 0101
```

As the IEEE 1800-2023 states
> The function $countbits counts the number of bits that have a specific set of values (e.g., 0, 1, x, z) in a
bit vector.
> — $countbits ( expression , control_bit { , control_bit } )
> This function returns an int equal to the number of bits in expression whose values match one of the
control_bit entries. For example:
> — $countbits (expression, '1) returns the number of bits in expression having value 1.
> — $countbits (expression, '1, '0) returns the number of bits in expression having values
1 or 0.
> — $countbits (expression, 'x, 'z) returns the number of bits in expression having values x
or z

and here `8F` is rewritten in binary as `10001111` so there are 5 one's or x values. 

### Actual Behavior

The output I get is 
```txt
cnt = 1000
```

So I suppose it is because `x` values are unsupported by cxxrtl (considered as `0` for the countbits function, but as no warning was made for this, I did not know if this was either a bug, a design defect, or an implementation choice. 

Anyways thanks for the work on yosys !

